r_tge_confirm_letter_nest.sql:
select seq_no , account_name , data_refno , data_balance , data_group , confirm_date , membership_no from ( select substr(sc_acc_m_account_master.account_name,8,100) as account_name , sc_cls_confirm_data.membership_no , sc_cls_confirm_data.confirm_date , sc_cls_confirm_data.seq_no , sc_cls_confirm_data.data_refno , sc_cls_confirm_data.data_balance , sc_cls_confirm_data.data_group from sc_cls_confirm_data , sc_acc_m_account_master , sc_lon_m_rule where sc_cls_confirm_data.data_type = sc_lon_m_rule.loan_type and sc_acc_m_account_master.account_id = sc_lon_m_rule.account_id and sc_cls_confirm_data.data_group = 'LON' and sc_cls_confirm_data.data_balance > '0' /*WHERE*/ and sc_cls_confirm_data.membership_no = {0} and sc_cls_confirm_data.confirm_date = {1}
union all
select sc_dep_m_rule.deposit_name as account_name , sc_cls_confirm_data.membership_no , sc_cls_confirm_data.confirm_date , sc_cls_confirm_data.seq_no , sc_cls_confirm_data.data_refno , sc_cls_confirm_data.data_balance , sc_cls_confirm_data.data_group from sc_cls_confirm_data , sc_dep_m_rule where sc_cls_confirm_data.data_type = sc_dep_m_rule.deposit_type_code and sc_cls_confirm_data.data_group = 'DEP' and sc_cls_confirm_data.data_balance > '0' /*WHERE*/ and sc_cls_confirm_data.membership_no = {0} and sc_cls_confirm_data.confirm_date = {1} ) tab order by membership_no , seq_no
